/*
 * Stub of FFmpeg's auto-generated libavutil/avconfig.h.
 *
 * The real file is produced by `./configure` in the FFmpeg source
 * tree and varies by host. For jextract we only need a portable
 * default that lets the public headers compile against any
 * little-endian aligned-access platform we ship for (x86_64 or
 * aarch64 on Linux/macOS/Windows). The values below match what
 * configure produces on those targets.
 *
 * Re-run jextract whenever this file changes.
 */
#ifndef AVUTIL_AVCONFIG_H
#define AVUTIL_AVCONFIG_H
#define AV_HAVE_BIGENDIAN 0
#define AV_HAVE_FAST_UNALIGNED 1
#endif /* AVUTIL_AVCONFIG_H */
